def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    result = []
    start = nums[0]

    for num in nums[1:]:
        if num != start + 1:
            if start == num - 1:
                result.append(f'{start}-{num-1}')
            else:
                result.append(str(start))
            start = num

    if start == nums[-1]:
        result.append(str(start))
    else:
        result.append(f'{start}-{nums[-1]}')

    return ', '.join(result)
